// Leemos el body del webhook y calculamos
// si los vitales del paciente son críticos.

const body = $input.first().json.body || {};
const vitals = body.vitals || {};

const hasCriticalVitals = vitals.spo2 != null && vitals.spo2 < 92;

return [{
  json: {
    patientId: body.patientId || 'desconocido',
    age: body.age || null,
    spo2: vitals.spo2 ?? null,
    hasCriticalVitals
  }
}];
